
-- 1. Create Module 2 if not exists
DO $$
DECLARE
    v_module_id UUID;
BEGIN
    SELECT id INTO v_module_id 
    FROM public.course_modules 
    WHERE course_id = '5bdf783f-b42b-4e25-bef1-d707c632df42' AND title ILIKE '%Concept of God%' 
    LIMIT 1;

    IF v_module_id IS NULL THEN
        INSERT INTO public.course_modules (course_id, title, description, sort_order, is_published)
        VALUES ('5bdf783f-b42b-4e25-bef1-d707c632df42', 'Module 2: The Concept of God', 'Explore the Islamic concept of God, His nature, His names, and Tawheed.', 2, true)
        RETURNING id INTO v_module_id;
    END IF;

    -- Delete existing lessons to prevent duplicates on rerun
    DELETE FROM public.course_lessons WHERE module_id = v_module_id;

    -- Insert Lessons

    INSERT INTO public.course_lessons (
        module_id, course_id, title, description, content_type, 
        duration_minutes, sort_order, video_url, is_published, content_data
    ) VALUES (
        v_module_id, '5bdf783f-b42b-4e25-bef1-d707c632df42', 'Who is Allah? Introducing the Creator', 'An introduce to the unique Islamic concept of God – His nature, names, and relationship with creation.', 'video', 
        30, 1, 'https://www.youtube.com/watch?v=abc123', true, '{"pages":[{"page_number":1,"page_title":"Lesson Overview","content":[{"type":"text","content":"# Page 1 – Lesson Overview\n\n**Goal:** To introduce the Islamic concept of God – His nature, names, and relationship with creation.\n\n### Key Questions\n- What does the word \"Allah\" mean?\n- How does Allah describe Himself in the Quran?\n- What is the difference between Allah and the concept of God in other traditions?\n\n**Time Estimate:** 30 minutes\n\n### Key Terms\n- **Allah** – the personal name of God in Islam, denoting the one true God.\n- **Ilah** – god or deity.\n- **Rabb** – Lord, Sustainer, Cherisher.\n- **Rahman** – The Most Merciful."}]},{"page_number":2,"page_title":"Core Video","content":[{"type":"video","url":"https://www.youtube.com/watch?v=abc123"},{"type":"text","content":"# Page 2 – Core Video\n\n**Yasir Qadhi – \"Who is Allah? An Introduction to the Divine\"**\n\n**Video Description:** In this talk, Yasir Qadhi explains the meaning of the name \"Allah,\" His attributes, and how He is distinct from all created beings. He draws from the Quran and authentic Hadith.\n\n### Chapters\n- 0:00 – Introduction\n- 3:20 – The meaning of \"Allah\"\n- 8:10 – Allah’s self‑disclosure in the Quran\n- 15:30 – The relationship between God and creation\n- 22:00 – Common misconceptions\n- 28:00 – Conclusion"}]},{"page_number":3,"page_title":"Companion Guide","content":[{"type":"text","content":"# Page 3 – Companion Guide\n\n### Summary of Key Points\n- \"Allah\" is the unique, personal name of the one true God. It has no plural or feminine form.\n- Allah is not a \"god\" among many; He is the only God, the Creator and Sustainer of everything.\n- He describes Himself through His 99 Beautiful Names and Attributes, which reveal His nature.\n- Allah is completely unlike His creation – \"There is nothing like unto Him\" (42:11).\n- He is both transcendent (above and beyond) and immanent (close to His creation through His knowledge and mercy).\n\n### Deeper Explanation\nThe name \"Allah\" is derived from the Arabic root \"aliha,\" meaning to worship, or from \"ilah\" (god) with the definite article \"al‑\" (the), hence \"the God.\" It emphasizes that He alone is deserving of worship. Pre‑Islamic Arabs recognized a supreme deity they called Allah, but they also worshipped other gods alongside Him.\n\n### Quranic Verses\n- **Surah Al-Ikhlas 112:1‑4** – \"Say, ''He is Allah, [who is] One, Allah, the Eternal Refuge.''\"\n- **Surah Ash-Shura 42:11** – \"…There is nothing like unto Him, and He is the Hearing, the Seeing.\"\n\n### Hadith References\n- The Prophet (peace be upon him) said, \"Allah has ninety‑nine names, one hundred less one; whoever learns them and preserves them will enter Paradise.\" (Bukhari, 6410)"}]},{"page_number":4,"page_title":"Reflection Journal","content":[{"type":"reflection","content":"# Page 4 – Reflection Journal\n\n1. Before this lesson, what did you imagine when you heard the name \"Allah\"? Has this lesson changed that image?\n2. The Quran says, \"There is nothing like unto Him.\" How does this statement affect the way you think about God?\n3. Pick one of Allah’s names (e.g., Ar‑Rahman, Al‑Wadud). What does it mean to you personally?\n4. Write a short prayer (dua) addressing Allah by one of His names and expressing your need for Him."}]},{"page_number":5,"page_title":"Knowledge Check","content":[{"type":"quiz","id":"m2l1_q1","question":"The word ''Allah'' means:","options":["A) The moon god","B) The God, the one true deity","C) A prophet","D) An angel"],"correctIndex":1},{"type":"quiz","id":"m2l1_q2","question":"Which surah summarizes the oneness and uniqueness of Allah?","options":["A) Al-Fatiha","B) Al-Ikhlas","C) Al-Baqarah","D) Ya-Sin"],"correctIndex":1},{"type":"quiz","id":"m2l1_q3","question":"According to the Quran, Allah is closer to us than:","options":["A) Our parents","B) Our jugular vein","C) Our skin","D) Our thoughts"],"correctIndex":1}]}]}'::jsonb
    );

    INSERT INTO public.course_lessons (
        module_id, course_id, title, description, content_type, 
        duration_minutes, sort_order, video_url, is_published, content_data
    ) VALUES (
        v_module_id, '5bdf783f-b42b-4e25-bef1-d707c632df42', 'Tawheed Explained – The Heart of Islamic Belief', 'Understand the concept of Tawheed (monotheism) and its three categories.', 'video', 
        30, 2, 'https://www.youtube.com/watch?v=def456', true, '{"pages":[{"page_number":1,"page_title":"Lesson Overview","content":[{"type":"text","content":"# Page 1 – Lesson Overview\n\n**Goal:** Understand the concept of Tawheed (monotheism) and its three categories.\n\n### Key Questions\n- What does Tawheed mean?\n- What are the three categories of Tawheed?\n- How does Tawheed shape a Muslim’s life?"}]},{"page_number":2,"page_title":"Core Video","content":[{"type":"video","url":"https://www.youtube.com/watch?v=def456"},{"type":"text","content":"# Page 2 – Core Video\n\n**Omar Suleiman – \"The Three Categories of Tawheed\"**\n\n**Description:** Omar Suleiman breaks down the three aspects of Tawheed and explains why each is essential to Islamic faith.\n\n### Chapters\n- 0:00 – Introduction\n- 3:00 – Tawheed ar‑Rububiyyah\n- 8:30 – Tawheed al‑Uluhiyyah\n- 14:00 – Tawheed al‑Asma’ was‑Sifat\n- 20:00 – Practical implications\n- 25:00 – Conclusion"}]},{"page_number":3,"page_title":"Companion Guide","content":[{"type":"text","content":"# Page 3 – Companion Guide\n\n### Summary of Key Points\n- **Tawheed ar‑Rububiyyah**: Oneness of Lordship. (Believing Allah is the only Creator).\n- **Tawheed al‑Uluhiyyah**: Oneness of Worship. (Directing all prayer, inner love, trust fully to Allah only).\n- **Tawheed al‑Asma’ was‑Sifat**: Oneness of Names and Attributes. (Affirming description without distortion or comparing to creation)."}]},{"page_number":4,"page_title":"Reflection Journal","content":[{"type":"reflection","content":"# Page 4 – Reflection Journal\n\n1. Before this lesson, did you think of Tawheed simply as \"believing in one God\"? How has your understanding deepened?\n2. Why do you think Tawheed al‑Uluhiyyah (directing worship to Allah alone) is so central, even if one already believes He is the Creator?"}]},{"page_number":5,"page_title":"Knowledge Check","content":[{"type":"quiz","id":"m2l2_q1","question":"What are the three categories of Tawheed?","options":["A) Past, present, future","B) Tawheed ar‑Rububiyyah, al‑Uluhiyyah, al‑Asma’ was‑Sifat","C) Prophets, angels, books","D) Faith, deeds, character"],"correctIndex":1},{"type":"quiz","id":"m2l2_q2","question":"Tawheed ar‑Rububiyyah refers to:","options":["A) Worshipping Allah alone","B) Believing Allah is the only Lord and Creator","C) Affirming Allah''s names","D) Following the Sunnah"],"correctIndex":1}]}]}'::jsonb
    );

    INSERT INTO public.course_lessons (
        module_id, course_id, title, description, content_type, 
        duration_minutes, sort_order, video_url, is_published, content_data
    ) VALUES (
        v_module_id, '5bdf783f-b42b-4e25-bef1-d707c632df42', 'The 99 Names – An Overview', 'Introduce the beautiful names of Allah, their significance, and how they can be used in worship and daily life.', 'video', 
        30, 3, 'https://www.youtube.com/watch?v=ghi789', true, '{"pages":[{"page_number":1,"page_title":"Lesson Overview","content":[{"type":"text","content":"# Page 1 – Lesson Overview\n\n**Goal:** Introduce the beautiful names of Allah, their significance, and how they can be used in worship.\n\n### Key Questions\n- What are the 99 Names of Allah?\n- Why are they important?\n- How can we learn and live by them?"}]},{"page_number":2,"page_title":"Core Video","content":[{"type":"video","url":"https://www.youtube.com/watch?v=ghi789"},{"type":"text","content":"**Mufti Menk – \"Understanding the 99 Names of Allah\"**\n\nMufti Menk provides an overview of the 99 Names, their meanings, and their impact on a believer’s life."}]},{"page_number":3,"page_title":"Companion Guide","content":[{"type":"text","content":"# Page 3 – Companion Guide\n\n### Summary of Key Points\n- These names are not mere labels; they reveal who Allah is and how He relates to creation.\n- They can be categorized into names of majesty (Al‑Aziz) and names of beauty (Al‑Wadud).\n- Knowing Allah’s names deepens love, fear, and hope in Him."}]},{"page_number":4,"page_title":"Reflection Journal","content":[{"type":"reflection","content":"# Page 4 – Reflection Journal\n\n1. Which of Allah’s names do you feel most drawn to at this moment? Why?\n2. How does knowing that Allah is Ar‑Rahman (Most Merciful) affect your hope in His forgiveness?"}]},{"page_number":5,"page_title":"Knowledge Check","content":[{"type":"quiz","id":"m2l3_q1","question":"How many beautiful names does Allah have according to the famous hadith?","options":["A) 100","B) 99","C) 90","D) 120"],"correctIndex":1},{"type":"quiz","id":"m2l3_q2","question":"What does the Quran command us to do with these names?","options":["A) Memorize them only","B) Call upon Allah by them","C) Write them on walls","D) Recite them once a year"],"correctIndex":1}]}]}'::jsonb
    );

    INSERT INTO public.course_lessons (
        module_id, course_id, title, description, content_type, 
        duration_minutes, sort_order, video_url, is_published, content_data
    ) VALUES (
        v_module_id, '5bdf783f-b42b-4e25-bef1-d707c632df42', 'Allah as Creator – Al‑Khaliq', 'Deepen understanding of Allah’s attribute as the Creator and its implications for our worldview.', 'video', 
        30, 4, 'https://www.youtube.com/watch?v=jkl012', true, '{"pages":[{"page_number":1,"page_title":"Lesson Overview","content":[{"type":"text","content":"# Page 1 – Lesson Overview\n\n**Goal:** Deepen understanding of Allah’s attribute as the Creator and its implications for our worldview."}]},{"page_number":2,"page_title":"Core Video","content":[{"type":"video","url":"https://www.youtube.com/watch?v=jkl012"},{"type":"text","content":"**Nouman Ali Khan – \"Allah the Creator – Signs in the Universe\"**\n\nNouman Ali Khan reflects on the Quranic verses that invite us to ponder creation."}]},{"page_number":3,"page_title":"Companion Guide","content":[{"type":"text","content":"# Page 3 – Companion Guide\n\n### Summary of Key Points\n- **Al‑Khaliq** is the One who creates everything from nothing.\n- Creation is not a one‑time act; Allah continuously sustains and creates.\n- Pondering creation strengthens faith and gratitude."}]},{"page_number":4,"page_title":"Reflection Journal","content":[{"type":"reflection","content":"# Page 4 – Reflection Journal\n\n1. Spend a few minutes looking at something in nature. Write down what it tells you about its Creator.\n2. How does knowing that you are created by Al‑Khaliq affect your sense of purpose?"}]},{"page_number":5,"page_title":"Knowledge Check","content":[{"type":"quiz","id":"m2l4_q1","question":"What does the name Al‑Khaliq mean?","options":["A) The Sustainer","B) The Creator","C) The Forgiving","D) The Loving"],"correctIndex":1},{"type":"quiz","id":"m2l4_q2","question":"According to the Quran, Allah creates by simply saying:","options":["A) Thinik","B) Be","C) Make","D) Appear"],"correctIndex":1}]}]}'::jsonb
    );

    INSERT INTO public.course_lessons (
        module_id, course_id, title, description, content_type, 
        duration_minutes, sort_order, video_url, is_published, content_data
    ) VALUES (
        v_module_id, '5bdf783f-b42b-4e25-bef1-d707c632df42', 'Allah as Sustainer – Ar‑Razzaq', 'Understand Allah’s attribute as the Provider and how it shapes our trust and gratitude.', 'video', 
        30, 5, 'https://www.youtube.com/watch?v=mno345', true, '{"pages":[{"page_number":1,"page_title":"Lesson Overview","content":[{"type":"text","content":"# Page 1 – Lesson Overview\n\n**Goal:** Understand Allah’s attribute as the Provider and how it shapes our trust and gratitude."}]},{"page_number":2,"page_title":"Core Video","content":[{"type":"video","url":"https://www.youtube.com/watch?v=mno345"},{"type":"text","content":"**Yasir Qadhi – \"Ar‑Razzaq: The Provider\"**\n\nYasir Qadhi explains the meaning of Ar‑Razzaq."}]},{"page_number":3,"page_title":"Companion Guide","content":[{"type":"text","content":"# Page 3 – Companion Guide\n\n### Summary of Key Points\n- Ar‑Razzaq creates provision and delivers it to all creatures.\n- Provision (rizq) includes all needed for life: health, knowledge, food.\n- Gratitude (shukr) increases blessings."}]},{"page_number":4,"page_title":"Reflection Journal","content":[{"type":"reflection","content":"# Page 4 – Reflection Journal\n\n1. List five things you received today that are provision from Allah.\n2. How can trusting Ar‑Razzaq relieve anxiety?"}]},{"page_number":5,"page_title":"Knowledge Check","content":[{"type":"quiz","id":"m2l5_q1","question":"What does Ar‑Razzaq mean?","options":["A) The Creator","B) The Provider","C) The Forgiving","D) The Loving"],"correctIndex":1},{"type":"quiz","id":"m2l5_q2","question":"What increases provision according to Surah Ibrahim?","options":["A) Hard work","B) Gratitude","C) Saving money","D) Complaining"],"correctIndex":1}]}]}'::jsonb
    );

END $$;
